export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十四點三十分。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠把未裁切的照片打開在螢幕左半邊。照片被水泡皺了，邊角捲起來，但畫面是完整的——比校史館牆上那張更大、更寬，沒有被裁過。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "照片裡。一個小男孩。穿小雨衣。站在一個白襯衫男人旁邊。男人手裡拿著錄音筆。中間偏右，一個低馬尾女人掛著相機。右側邊緣，一個短髮年輕人站在承包商和校方之間。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "背景布條：「南翼整修後防災演練暨安全說明會」。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕右半邊是音訊播放器。波形圖。許星棠從記憶卡裡找到了一段錄音——時間戳記是十年前火災當晚。檔名只有一串數字。長度三分四十二秒。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這段錄音是我媽相機自動錄的。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "她那台相機有墜落觸發錄音的功能。相機摔到地上的時候自動開始錄。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "三分四十二秒。之後電池斷了。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把耳機遞給顧言。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "閉眼睛。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "先聽。不要想。讓聲音進來。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）好。", background: Background.Chapter_8_Ch8_Act7_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他接過耳機。戴上。閉上眼睛。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "世界暗下來了。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠按下播放。", background: Background.Chapter_8_Ch8_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一秒。雨聲。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是窗外那種安靜的細雨。是暴雨。是打在鐵皮和水泥上的、密集的、像機槍掃射一樣的雨聲。從耳機裡灌進來，填滿整個頭顱。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第十秒。鐘聲。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "學校的鐘。不是正常報時的那種均勻的噹——噹——噹。是不規則的。短的。急的。像有人在拼命搖。像在示警。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯鐘。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二十秒。另一種聲音混進來了。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "低沉的。持續的。不是雷。不是雨。是一種從建築結構裡傳出來的、像動物在呻吟一樣的聲音。木頭在燒。鋼筋在膨脹。水泥在裂。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯火。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是火災。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是十年前。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四十秒。人聲。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是對著麥克風說的。是遠處的。被雨和火和建築的呻吟壓著的。聽不清字。只有音調——高的、急的、在喊什麼。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——腳步聲。跑的。很近。鞋底踩在積水上的聲音。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個男人的聲音。近了。壓低了。氣音。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "別出聲。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯爸。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是爸的聲音。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和碎片裡的一模一樣。但更清楚了。更近了。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "錄音繼續。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "布料摩擦的聲音。什麼東西被展開。然後——一個重量壓下來。濕的。重的。帶著煙味和一種洗衣粉的味道。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）外套。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）濕外套。他蓋在我頭上。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "透過外套的布料，聲音變得悶了。雨聲遠了。火的聲音遠了。但有一個聲音更近了——就在耳朵旁邊。氣音。嘴唇幾乎貼著耳廓。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親的聲音。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "完整的。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "不要回頭看火。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字。很穩。不是慌張的。不是絕望的。是一個做了決定的人在交代最後一件事。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不要回頭看火。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要——回頭——看——火。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是前半句。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我一直聽到的「不要回頭」——後面還有。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「看火」。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不是叫我不要回頭。他是叫我不要回頭看火。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "錄音沒有停。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親的聲音繼續。同一口氣。沒有斷。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "六個字。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音壓得更低了。幾乎是氣音。但每一個字都清楚。像他用了最後的力氣，把這幾個字一個一個推進顧言的耳朵裡。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）海上的——", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）燈。", background: Background.Chapter_8_Ch8_Act7_S1, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他睜開了眼睛。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室。螢幕。照片。許星棠。雨聲從窗外傳進來。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他看見的不是這些。", background: Background.Chapter_8_Ch8_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看見了。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十年前。南翼走廊。火從另一側燒過來。走廊很長。門下面的光是橘紅色的、跳動的。空氣裡是焦的、辣的、嗆的味道。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親蹲在他面前。白襯衫。袖子捲到手肘。手裡拿著一件外套——濕的。他把外套展開，蓋在他頭上和肩膀上。動作很輕。很快。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後父親湊近他的耳朵。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音很低。壓到幾乎是氣音。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "完整的。一句話。十個字。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有斷。沒有缺。沒有被剪掉。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它一直都在。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要回頭看火。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是——", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這不是拋下我。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手在抖。不是冷。不是怕。是什麼東西在胸腔裡裂開了——不是碎，是開。像一扇被焊死了十年的門，突然從裡面被推開。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我一直以為「不要回頭」是叫我別管他。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）以為他自己要走。以為他放棄了。以為他丟下我了。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不是。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他不是叫我不要回頭。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他是叫我不要回頭看火。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要被火定住。不要被恐懼定住。不要站在那裡看著火——", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）要跑。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）要往能活下去的方向跑。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想起來了。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是碎片。不是閃回。是完整的。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親把他推向窗邊。不是推開他——是推向他能活下去的方向。濕外套蓋在他頭上，擋住火星和煙。父親的手按在他後背上，推著他往前走。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯他在推我。往前。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "透過外套的縫隙，他看見了窗外。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨。夜。火光把走廊照成橘紅色。但窗外——更遠的地方——海面上有一點光。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白的。穩定的。不閃。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是火。是燈塔。是漁船的燈。是海上任何一種會亮到天亮的東西。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親叫看的——就是那個。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我見過。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）每天早上醒來。宿舍窗外。灰色的海面上。一點白光。我每次都以為是夢裡的火光——", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是火光。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是燈。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是爸叫我去看的那盞燈。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉上眼睛。又睜開。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "眼眶是熱的。但沒有掉下來。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不是不想哭。是這個東西太大了，大到眼淚還不知道怎麼從這麼深的地方流出來。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯爸。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你不是拋下我。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你是在叫我活下去。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十年了。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我花了十年才聽完這句話。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著他。她沒有說話。她只是看著。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見了他的表情變化——不是崩潰。不是嚎啕。是一種很安靜的、從內部發生的鬆動。像冰在解凍。不是轟然碎裂，是慢慢地、一層一層地，開始有水流出來。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "想到了。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "完整的。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他說出來了。十個字。一個字都沒有斷。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上的光標還在閃。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "回頭前，聽見的那句話。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這就是密碼。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這就是爸留給我的。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他伸手。手指放在鍵盤上。不抖了。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他輸入。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "按確認。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯拜託。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕閃了一下。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "綠字。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "解密成功。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯開了。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "檔案目錄展開了。三個資料夾。音訊。文件。圖片。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠的身體微微前傾。她的手指在觸控板上移動，點開第一個資料夾。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她沒有立刻看內容。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她先轉頭看了顧言一眼。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你爸等了十年。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你終於打開了。", background: Background.Chapter_8_Ch8_Act7_S2, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有回答。他看著螢幕上展開的檔案目錄。綠色的。解密成功。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在打。舊圖書室裡很安靜。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想起父親蹲在他面前。白襯衫。袖子捲到手肘。濕外套蓋在他頭上。嘴唇貼著他的耳朵。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有回頭。", background: Background.Chapter_8_Ch8_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十年了。他終於沒有回頭。", background: Background.Chapter_8_Ch8_Act7_S2 },
];
